class CanalTreaty:
    def __init__(self):
        self.usa_agrees = False
        self.uk_agrees = False

    def usa_approves(self):
        self.usa_agrees = True
        return self.check_neutrality()

    def uk_approves(self):
        self.uk_agrees = True
        return self.check_neutrality()

    def check_neutrality(self):
        if self.usa_agrees and self.uk_agrees:
            return "Canal construction approved under neutral terms."
        return "Canal construction requires mutual agreement."

# Example usage:
treaty = CanalTreaty()
print(treaty.usa_approves())  # Output: 'Canal construction requires mutual agreement.'
print(treaty.uk_approves())   # Output: 'Canal construction approved under neutral terms.'
